# policies/ai_deployment.rego
# OPA Rego policy for agentic AI deployment compliance gate.
package ai.compliance

import future.keywords.if
import future.keywords.in

default allow := false
default violations := []

# Gather all violations before deciding.
allow if {
    count(violations) == 0
}

violations := [v |
    some check in checks
    not check.passed
    v := check.message
]

checks := [
    check_data_residency,
    check_model_card_present,
    check_pii_handling,
    check_human_review_approved,
]

# Data must reside in approved regions.
check_data_residency := {"passed": true, "message": ""} if {
    input.deployment.region in data.approved_regions
} else := {"passed": false, "message": concat("", [
    "Data residency violation: region ", input.deployment.region,
    " not in approved list"
])}

# Model card must be present and signed.
check_model_card_present := {"passed": true, "message": ""} if {
    input.artifact.model_card_hash != ""
    input.artifact.model_card_signed == true
} else := {"passed": false, "message": "Model card absent or unsigned"}

# High-risk systems must declare PII handling policy.
check_pii_handling := {"passed": true, "message": ""} if {
    input.system.risk_tier != "high"
} else := {"passed": true, "message": ""} if {
    input.system.risk_tier == "high"
    input.artifact.dpia_completed == true
    input.artifact.dpia_hash != ""
} else := {"passed": false, "message": "High-risk system missing completed DPIA"}

# High and medium risk require recorded human approval.
check_human_review_approved := {"passed": true, "message": ""} if {
    input.system.risk_tier == "low"
} else := {"passed": true, "message": ""} if {
    input.system.risk_tier in {"medium", "high"}
    input.review.status == "approved"
    input.review.approver_id != ""
} else := {"passed": false, "message": concat("", [
    "Human review required for risk tier ", input.system.risk_tier,
    " — status: ", input.review.status
])}
